import os, base64, urllib.request, json, py_compile, tempfile, re

token = os.environ.get("GITHUB_TOKEN","")
repo  = "dperuffo/estudo-de-rede"

TRANS_B64 = ""
trans_bytes = base64.b64decode(TRANS_B64.encode())

# ── Passo 1: Sobe translations_app.py para o GitHub ─────────────
def _push(path_repo, content_bytes, msg):
    url = "https://api.github.com/repos/" + repo + "/contents/" + path_repo
    req = urllib.request.Request(url, headers={
        "Authorization": "token " + token,
        "Accept": "application/vnd.github.v3+json"
    })
    sha = None
    try:
        with urllib.request.urlopen(req) as r: sha = json.loads(r.read()).get("sha")
    except Exception: pass
    encoded = base64.b64encode(content_bytes).decode()
    payload = {"message": msg, "content": encoded}
    if sha: payload["sha"] = sha
    req2 = urllib.request.Request(url, data=json.dumps(payload).encode(), method="PUT", headers={
        "Authorization": "token " + token,
        "Content-Type": "application/json",
        "Accept": "application/vnd.github.v3+json"
    })
    with urllib.request.urlopen(req2) as r:
        return json.loads(r.read())["commit"]["sha"][:7]

sha1 = _push("estudo-de-rede/translations_app.py", trans_bytes, "feat: modulo de traducoes PT/EN")
print(f"GITHUB OK translations_app.py: commit {sha1}")

# ── Passo 2: Atualiza estudo_de_rede.py ─────────────────────────
arquivo = "/app/estudo_de_rede.py"
with open(arquivo, "r", encoding="utf-8") as f: src = f.read()
