# Valida sintaxe
with tempfile.NamedTemporaryFile(suffix=".py", delete=False, mode="w", encoding="utf-8") as tmp:
    tmp.write(src)
    tp = tmp.name
try:
    py_compile.compile(tp, doraise=True)
    print("Sintaxe OK: estudo_de_rede.py")
except py_compile.PyCompileError as e:
    print(f"ERRO SINTAXE: {e}")
    exit(1)

with open(arquivo, "w", encoding="utf-8") as f: f.write(src)

sha2 = _push("estudo-de-rede/estudo_de_rede.py", src.encode("utf-8"),
             "feat: i18n PT/EN na aplicacao — seletor sidebar + nav traduzido")
print(f"GITHUB OK estudo_de_rede.py: commit {sha2}")

